class Solution:
    def zeroFilledSubarray(self, nums: []) -> int:
        starts, ends = [],[]
        start = -1
        for idx, num in enumerate(nums):
            if num == 0 and start == -1:
                starts.append(idx)
                start = idx
            elif num != 0 and start != -1:
                ends.append(idx-1)
                start = -1

            if idx == len(nums)-1 and start != -1:
                ends.append(idx)

        count = 0
        for run in range(0, len(starts)):
            length = ends[run] - starts[run]
            for zidx in range (0, length+1):
                count += length - zidx + 1
                
        return count

